    {
      "task": "описание задачи",
      "completed": false,
      "priority": "High/Medium/Low",
      "deadline": "срок выполнения"
    }
  ],
  "summary": "краткое резюме чеклиста",
  "total_tasks": 0,
  "completed_tasks": 0
}

